/**
 * @brief Calculates the sum of all numbers present in a string.
 *
 * This function iterates through the string, extracts consecutive digit
 * sequences to form numbers, and sums them up.
 *
 * @param str The input string containing numbers and other characters.
 * @return The sum of all numbers found in the string.
 */
int findSum(const std::string& str) {
    std::string temp = "0";
    int sum = 0;
    // Iterate through each character in the string
    for (char ch : str) {
        // If the character is a digit, append it to the temporary string
        if (std::isdigit(static_cast<unsigned char>(ch))) {
            temp += ch;
        }
        // If the character is not a digit, it marks the end of a number
        else {
            // Convert the number string to an integer and add to the total sum
            sum += std::stoi(temp);
            // Reset the temporary string to "0" for the next number
            temp = "0";
        }
    }
    // Add the last number found after the loop finishes
    return sum + std::stoi(temp);
}

