// Function to find the ceiling of x in a sorted array arr[low..high]
// The ceiling is the smallest element in the array greater than or equal to x
int ceilSearch(int arr[], int low, int high, int x) {
    int mid;
    // If x is smaller than or equal to the first element, then the first element is the ceiling
    if (x <= arr[low]) {
        return low;
    }
    // If x is greater than the last element, then the ceiling does not exist in the array
    if (x > arr[high]) {
        return -1;
    }
    // Find the middle index
    mid = low + (high - low) / 2; // Safer way to calculate mid to prevent overflow
    // If x is same as the middle element, then mid is the ceiling
    if (arr[mid] == x) {
        return mid;
    }
    // If x is greater than arr[mid], then the ceiling is in the right half
    else if (arr[mid] < x) {
        // If x is smaller than or equal to the element at mid+1, then mid+1 is the ceiling
        if (mid + 1 <= high && x <= arr[mid + 1]) {
            return mid + 1;
        } else {
            // Otherwise, recurse for the right subarray
            return ceilSearch(arr, mid + 1, high, x);
        }
    }
    // If x is smaller than arr[mid], then the ceiling is in the left half or is arr[mid] itself
    else {
        // If x is greater than the element at mid-1, then mid is the ceiling
        if (mid - 1 >= low && x > arr[mid - 1]) {
            return mid;
        } else {
            // Otherwise, recurse for the left subarray
            return ceilSearch(arr, low, mid - 1, x);
        }
    }
}

