bool areConsecutive(int arr[], int n) {
    if (n < 1) {
        return false;
    }
    // Find the minimum and maximum elements in the array
    int minVal = *std::min_element(arr, arr + n);
    int maxVal = *std::max_element(arr, arr + n);
    // Check if the difference between max and min equals n-1
    if (maxVal - minVal + 1 == n) {
        // Create a boolean vector to mark visited elements.
        // It is initialized to false by default.
        std::vector<bool> visited(n, false);
        for (int i = 0; i < n; i++) {
            // If we see an element again, then it's a duplicate and numbers are not consecutive
            if (visited[arr[i] - minVal] == true) {
                return false;
            }
            // Mark the element as visited
            visited[arr[i] - minVal] = true;
        }
        // If all elements are unique and within the range [min, max], they are consecutive
        return true;
    }
    // If (max - min + 1) is not equal to n, then they are not consecutive
    return false;
}

