bool checkDivisibility(std::string num) {
    int length = num.length();
    // A single digit '0' is divisible by 13
    if (length == 1 && num[0] == '0') {
        return true;
    }
    // If the length is not a multiple of 3, add 0s at the end
    // to make it a multiple of 3. This is equivalent to multiplying
    // the number by 10 or 100. Since 10 and 13 are coprime,
    // this does not affect the divisibility by 13.
    if (length % 3 == 1) {
        num += "00";
        length += 2;
    } else if (length % 3 == 2) {
        num += "0";
        length += 1;
    }
    int sum = 0;
    int p = 1; // Used for alternating sum (+, -, +, ...)
    // Process the number in groups of 3 from right to left
    for (int i = length - 1; i >= 0; i--) {
        int group = 0;
        // Create a 3-digit number from a group of 3 characters
        group += num[i--] - '0';
        group += (num[i--] - '0') * 10;
        group += (num[i] - '0') * 100;
        // Add the group to the sum with the correct sign
        sum = sum + group * p;
        // Invert the sign for the next group
        p *= -1;
    }
    // The original number is divisible by 13 if the absolute value of the sum is.
    sum = std::abs(sum);
    return (sum % 13 == 0);
}

