// This function calculates nCr % p using dynamic programming.
// It's a space-optimized version of building Pascal's Triangle.
int nCrModp(int n, int r, int p) {
    // If r is greater than n, nCr is 0.
    if (r > n) {
        return 0;
    }
    // Handle the case where r is 0 or r is n, as nC0 = nCn = 1.
    if (r == 0 || r == n) {
        return 1;
    }
    // Pascal's Triangle property: nCr = nC(n-r).
    // We can use the smaller value of r to optimize.
    if (r > n - r) {
        r = n - r;
    }
    // Create a vector to store the intermediate results of C(i, j).
    // C[j] will store the value of iCj.
    // The vector is initialized with zeros.
    std::vector<int> C(r + 1, 0);
    C[0] = 1; // Base case: nC0 is always 1.
    // Iterate through each number from 1 to n to build up the values.
    for (int i = 1; i <= n; i++) {
        // Fill the C vector from right to left. This is crucial for the
        // space-optimized approach, as we use C(i-1, j-1) to calculate
        // C(i, j), and we don't want to overwrite the C(i-1, j-1) value
        // before it's used to calculate C(i-1, j).
        for (int j = std::min(i, r); j > 0; j--) {
            // Pascal's identity: C(i, j) = C(i-1, j) + C(i-1, j-1)
            C[j] = (C[j] + C[j - 1]) % p;
        }
    }
    return C[r];
}

