/**
 * @brief Finds the number of ways to get a sum 'x' by throwing 'n' dice, each with 'm' faces.
 *
 * This function uses dynamic programming to solve the problem.
 *
 * @param m The number of faces on each die (from 1 to m).
 * @param n The number of dice.
 * @param x The target sum.
 * @return The total number of ways to achieve the sum 'x'.
 */
long long findWays(int m, int n, int x) {
    // Create a 2D table to store results of subproblems.
    // table[i][j] will store the number of ways to get sum 'j' with 'i' dice.
    // Initialize all entries to 0.
    std::vector<std::vector<long long>> table(n + 1, std::vector<long long>(x + 1, 0));
    // Base case: With 1 die, there is 1 way to get any sum from 1 to m.
    for (int j = 1; j <= m && j <= x; j++) {
        table[1][j] = 1;
    }
    // Fill the table in a bottom-up manner.
    // 'i' represents the number of dice.
    for (int i = 2; i <= n; i++) {
        // 'j' represents the target sum.
        for (int j = 1; j <= x; j++) {
            // 'k' represents the value of the current die's roll.
            for (int k = 1; k < j && k <= m; k++) {
                // The number of ways to get sum 'j' with 'i' dice is the sum of ways
                // to get the remaining sum 'j-k' with 'i-1' dice.
                table[i][j] += table[i - 1][j - k];
            }
        }
    }
    return table[n][x];
}

