int numberofways(int n, int m) {
    // Create a 2D vector to store the DP states, initialized to 0.
    std::vector<std::vector<int>> dp(n + 2, std::vector<int>(n + 2, 0));
    // Base case: There is one way to form a sum of 0 (by picking no numbers).
    // The state dp[0][k] for any k represents the number of ways to form sum 0.
    // We initialize dp[0][n+1] = 1 as a starting point for the recurrence.
    dp[0][n + 1] = 1;
    // Iterate from the largest possible number (n) down to m.
    for (int k = n; k >= m; k--) {
        // For each number k, calculate the number of ways to form sums from 0 to n.
        for (int i = 0; i <= n; i++) {
            // The number of ways to form sum 'i' using numbers >= k
            // is the sum of:
            // 1. Ways to form sum 'i' using numbers >= k+1 (i.e., not using k).
            dp[i][k] = dp[i][k + 1];
            // 2. Ways to form sum 'i-k' using numbers >= k (i.e., using k at least once).
            if (i - k >= 0) {
                dp[i][k] = (dp[i][k] + dp[i - k][k]);
            }
        }
    }
    // The result is the number of ways to form sum 'n' using numbers >= m.
    return dp[n][m];
}

