int lastPosition(int n, int m, int k) {
    // If the number of items to be distributed is less than or equal to
    // the number of positions from k to the end of the circle
    if (m <= n - k + 1) {
        return m + k - 1;
    }
    // If the items are more, we need to wrap around the circle.
    // First, distribute items until the end of the circle (position n).
    m = m - (n - k + 1);
    // Now, the remaining items (m) are distributed from the beginning (position 1).
    // The final position will be the remainder of m divided by n.
    // If the remainder is 0, it means the last item goes to the nth position.
    return (m % n == 0) ? n : (m % n);
}

