int minPalPartion(const std::string& str) {
    int n = str.length();
    // Create two 2D arrays to build the solution in a bottom-up manner.
    // C[i][j] = Minimum number of cuts needed for a palindrome partitioning of substring str[i..j]
    // P[i][j] = true if substring str[i..j] is a palindrome, else false
    std::vector<std::vector<int>> C(n, std::vector<int>(n));
    std::vector<std::vector<bool>> P(n, std::vector<bool>(n));
    // Every substring of length 1 is a palindrome and needs 0 cuts.
    for (int i = 0; i < n; i++) {
        P[i][i] = true;
        C[i][i] = 0;
    }
    // L is the substring length. We build the solution in a bottom-up manner by
    // considering substrings of length 2 to n.
    for (int L = 2; L <= n; L++) {
        // For a substring of length L, iterate through all possible starting indices.
        for (int i = 0; i < n - L + 1; i++) {
            int j = i + L - 1; // Set the ending index
            // Check if the substring is a palindrome.
            if (L == 2) {
                P[i][j] = (str[i] == str[j]);
            } else {
                P[i][j] = (str[i] == str[j]) && P[i + 1][j - 1];
            }
            // If str[i..j] is a palindrome, then C[i][j] is 0.
            if (P[i][j] == true) {
                C[i][j] = 0;
            } else {
                // If it's not a palindrome, we need to make a cut.
                // We try cutting at every possible position 'k' between i and j.
                C[i][j] = INT_MAX;
                for (int k = i; k < j; k++) {
                    C[i][j] = std::min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                }
            }
        }
    }
    // The result for the entire string is in C[0][n-1].
    return C[0][n - 1];
}

