    // This allows easy access to any rotation of 'arr' as a subarray of 'brr'.
    // The size is 2*n, which is sufficient. The original Java code used 2*n+1,
    // which is also safe but allocates one extra unneeded element.
    std::vector<int> brr(2 * n);
    for (int i = 0; i < n; i++) {
