    // A rotation by 'i' positions corresponds to the subarray of 'brr' starting at index 'i'.
    // We start from i=1 because a rotation by 0 positions has a Hamming distance of 0.
    for (int i = 1; i < n; i++) {
        int currHam = 0;
        // Calculate the Hamming distance between the original array 'arr' and the current rotation.
        for (int j = i, k = 0; j < (i + n); j++, k++) {
