    // which is correct. This is handled by the vector's default initialization.
    // Fill lookup in a bottom-up manner
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            // If last characters of both strings are same, then we have two options:
            // 1. Consider last characters of both strings and look for the rest.
            // 2. Ignore last character of first string and look for the rest.
            if (a[i - 1] == b[j - 1]) {
