int evenSum(int n) {
    // In C++, std::vector is a common way to create dynamic arrays.
    // This creates a 2D vector of size (n+1) x (n+1).
    std::vector<std::vector<int>> C(n + 1, std::vector<int>(n + 1));
    int i, j;
    // This part calculates Pascal's triangle (binomial coefficients).
    // C[i][j] will store the value of "i choose j".
    for (i = 0; i <= n; i++) {
        // Math.min becomes std::min in C++.
        for (j = 0; j <= std::min(i, n); j++) {
            // Base cases for the edges of the triangle.
            if (j == 0 || j == i) {
                C[i][j] = 1;
            }
            // Pascal's identity: C(i, j) = C(i-1, j-1) + C(i-1, j).
            else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
            }
        }
    }
    int sum = 0;
    // Summing up the coefficients C(n, k) where k is even.
    for (i = 0; i <= n; i += 2) {
        sum += C[n][i];
    }
    return sum;
}

