int findSubarraySum(const std::vector<int>& arr) {
    int n = arr.size();
    int res = 0;
    std::unordered_map<int, int> m;
    // Iterate through all possible subarrays
    for (int i = 0; i < n; ++i) {
        int sum = 0;
        for (int j = i; j < n; ++j) {
            // Calculate sum of subarray from i to j
            sum += arr[j];
            // Increment the frequency of this sum in the map
            m[sum]++;
