bool isPowerOfFour(int n) {
    int count = 0;
    // n & (n - 1) is a trick to check if n is a power of 2.
    // If n is a power of 2, it has only one bit set to 1,
    // and (n - 1) will have all bits set to 1 up to that position.
    // So their bitwise AND will be 0.
    int x = n & (n - 1);
    // A power of four must be a positive number and a power of two.
    if (n > 0 && x == 0) {
        // Now, we need to check if the single set bit is at an even position.
        // (0, 2, 4, ... from the right)
        // 4^0 = 1 (bit 0)
        // 4^1 = 4 (bit 2)
        // 4^2 = 16 (bit 4)
        // The loop counts the number of right shifts to get to 1,
        // which is equivalent to the position of the set bit.
        while (n > 1) {
            n >>= 1;
            count += 1;
        }
        // If the count (bit position) is even, it's a power of four.
        return (count % 2 == 0) ? true : false;
    }
    return false;
}

