int floorSearch(int arr[], int n, int x) {
    // If x is greater than or equal to the last element,
    // then the last element is the floor.
    if (x >= arr[n - 1]) {
        return n - 1;
    }
    // If x is smaller than the first element,
    // then no floor exists in the array.
    if (x < arr[0]) {
        return -1;
    }
    // Linearly search for the index of the floor.
    for (int i = 1; i < n; i++) {
        if (arr[i] > x) {
            return (i - 1);
        }
    }
    return -1;
}

