int countFriendsPairings(int n) {
    // std::vector is the idiomatic C++ equivalent of Java's dynamic array.
    std::vector<int> dp(n + 1);
    // Fill dp array in bottom-up manner
    for (int i = 0; i <= n; i++) {
        if (i <= 2) {
            dp[i] = i;
        } else {
            // Recurrence relation:
            // For the i-th person, they can either remain single or be paired up.
            // 1. If they remain single, the number of ways is dp[i-1].
            // 2. If they are paired, they can be paired with any of the previous (i-1) people.
            //    The number of ways is (i-1) * dp[i-2].
            dp[i] = dp[i - 1] + (i - 1) * dp[i - 2];
        }
    }
    return dp[n];
}

