int pairsInSortedRotated(int arr[], int n, int x) {
    // Find the pivot element. The pivot is the largest element.
    // The element after the pivot is the smallest element.
    int i;
    for (i = 0; i < n - 1; i++) {
        if (arr[i] > arr[i + 1]) {
            break;
        }
    }
    // l is the index of the smallest element
    int l = (i + 1) % n;
    // r is the index of the largest element
    int r = i;
    int cnt = 0;
    // Stop when l and r meet
    while (l != r) {
        // If we find a pair with sum x
        if (arr[l] + arr[r] == x) {
            cnt++;
            // This condition is to prevent l and r from crossing each other.
            // If l and r are adjacent, we must stop to avoid double counting.
            if (l == (r - 1 + n) % n) {
                return cnt;
            }
            // Move both pointers towards each other
            l = (l + 1) % n;
            r = (r - 1 + n) % n;
        }
        // If current pair sum is less, move the left pointer to increase sum
        else if (arr[l] + arr[r] < x) {
            l = (l + 1) % n;
        }
        // If current pair sum is greater, move the right pointer to decrease sum
        else {
            r = (r - 1 + n) % n;
        }
    }
    return cnt;
}

