    // Initialize the last column of L. Any pair of elements forms an AP of length 2.
    for (int i = 0; i < n; i++) {
        L[i][n - 1] = 2;
    }
    // Iterate from the second-to-last element 'j' down to the second element.
    // 'j' is considered as the middle element of a potential AP.
    for (int j = n - 2; j >= 1; j--) {
        int i = j - 1;
        int k = j + 1;
        // Use a two-pointer approach to find i and k such that
        // set[i], set[j], set[k] form an AP.
        while (i >= 0 && k <= n - 1) {
            if (set[i] + set[k] < 2 * set[j]) {
                k++;
            } else if (set[i] + set[k] > 2 * set[j]) {
                // For this i and j, there's no k that forms an AP.
                // The AP ending with set[i] and set[j] has length 2.
                L[i][j] = 2;
                i--;
            } else {
                // Found an AP: set[i], set[j], set[k]
                L[i][j] = L[j][k] + 1;
                llap = std::max(llap, L[i][j]);
