 * Reverses a string using a stack.
 * Note: The original Java function was named "recursiveReverse", but its
 * implementation is iterative. The name is kept for consistency.
 * This function modifies the input string in-place.
 *
 * @param str The string to be reversed, passed by reference.
 * @return The reversed string.
 */
std::string recursiveReverse(std::string& str) {
    std::stack<char> st;
    // Push all characters of the string onto the stack.
    for (char c : str) {
        st.push(c);
    }
    // Pop characters from the stack and overwrite the original string.
    for (size_t i = 0; i < str.length(); ++i) {
        str[i] = st.top();
        st.pop();
    }
    return str;
}

