    std::vector<std::vector<int>> T(m + 1, std::vector<int>(n + 1));
    for (int i = 0; i <= m; ++i) {
        for (int j = 0; j <= n; ++j) {
            // Base case: if m or n is 0, no sequence is possible.
            if (i == 0 || j == 0) {
                T[i][j] = 0;
            }
            // If m is less than n, it's not possible to form a sequence of length n.
            else if (i < j) {
                T[i][j] = 0;
