            // If n is 1, there are m possible sequences.
            else if (j == 1) {
                T[i][j] = i;
            }
            // Recurrence relation for other cases.
            else {
                T[i][j] = T[i - 1][j] + T[i / 2][j - 1];
            }
        }
    }
    return T[m][n];
