    // Create a 2D vector to store Pascal's triangle (binomial coefficients)
    // std::vector is used as a safer and more modern alternative to C-style arrays.
    std::vector<std::vector<int>> C(n + 1, std::vector<int>(n + 1));
    // Calculate binomial coefficients in a bottom-up manner
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= std::min(i, n); j++) {
            // Base cases: C(i, 0) = 1 and C(i, i) = 1
            if (j == 0 || j == i) {
                C[i][j] = 1;
            }
            // Use Pascal's identity: C(i, j) = C(i-1, j-1) + C(i-1, j)
            else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
            }
        }
    }
    // Sum the coefficients in the n-th row
    int sum = 0;
    for (int i = 0; i <= n; i++) {
        sum += C[n][i];
    }
    return sum;
}

