    // Move the second set of n bits to the rightmost position
    int set2 = (x >> p2) & ((1 << n) - 1);
    // XOR the two sets of bits
    int xor_val = (set1 ^ set2);
    // Put the XORed bits back to their original positions
    xor_val = (xor_val << p1) | (xor_val << p2);
