    for (int i = 0; i < n; ++i) {
        int left = 0, right = 0;
        // Count strictly increasing sequence to the left
        for (int j = i - 1; j >= 0; --j) {
            if (templeHeight[j] < templeHeight[j + 1]) {
                ++left;
            } else {
                break;
            }
        }
        // Count strictly decreasing sequence to the right
        for (int j = i + 1; j < n; ++j) {
            if (templeHeight[j] < templeHeight[j - 1]) {
                ++right;
            } else {
                break;
            }
        }
        // Sum of offerings is max of left or right sequence plus one
        sum += std::max(right, left) + 1;
    }
    return sum;
}

