long long countNonDecreasing(int n) {
    const int N = 10;
    long long count = 1;
    // This loop calculates the formula for combinations with repetition,
    // which is C(n + k - 1, k), where k is the number of items to choose (n)
    // and N is the number of types of items (10 digits).
    // The formula is C(n + 10 - 1, n) or C(n + 9, n).
    // The calculation is done iteratively to avoid overflow.
    for (int i = 1; i <= n; i++) {
        count *= (N + i - 1);
        count /= i;
    }
    return count;
}

