int countWays(int n) {
    // Create a vector of size n + 1 and initialize all elements to 0.
    std::vector<int> table(n + 1, 0);
    // Base case
    table[0] = 1;
    // Iterate from 1 to n-1 for the outer loop
    for (int i = 1; i < n; ++i) {
        // The inner loop updates the table for sums including the current number 'i'
        for (int j = i; j <= n; ++j) {
            table[j] += table[j - i];
        }
    }
    return table[n];
}

